const ocr = $json.ocr;
const piiParsed = $json.piiDetection;

const tokenMap = {};
const valueToToken = {};
const counters = {};

function getToken(type, value) {
  if (valueToToken[value]) return valueToToken[value];
  counters[type] = (counters[type] || 0) + 1;
  const token = '[' + type + '_' + counters[type] + ']';
  tokenMap[token] = value;
  valueToToken[value] = token;
  return token;
}

const piiByPage = {};
for (const p of (piiParsed.pages || [])) {
  piiByPage[p.pageNumber] = p.piiItems || [];
}

const tokenizedPages = (ocr.pages || []).map(page => {
  let text = page.text;
  const items = piiByPage[page.pageNumber] || [];

  // Dedupe by exact value first - the LLM may report the same value once per
  // occurrence in the source text, but a single global replace already
  // handles every occurrence, so re-processing duplicates would falsely
  // report them as "not found" the second time around.
  const seen = new Set();
  const deduped = [];
  for (const item of items) {
    if (!item.value || seen.has(item.value)) continue;
    seen.add(item.value);
    deduped.push(item);
  }

  const sorted = deduped.sort((a, b) => (b.value || '').length - (a.value || '').length);
  const notFound = [];
  for (const item of sorted) {
    const token = getToken(item.type || 'OTHER_PII', item.value);
    if (text.includes(item.value)) {
      text = text.split(item.value).join(token);
    } else {
      notFound.push(item);
    }
  }
  return { pageNumber: page.pageNumber, text, flaggedElements: page.flaggedElements || [], piiNotFound: notFound };
});

