const data = $json;
const fileName = data.fileName || '';

// Optional filename convention: "<name>__to-<lang>.pdf" lets a specific
// target language be requested per file without hardcoding a language pair.
const match = fileName.match(/__to-([a-zA-Z-]+)\./);
let targetLanguage = match ? match[1].toLowerCase() : null;

if (!targetLanguage) {
  // Default policy for ABC Ling's primary caseload: EN<->TR. Any other
  // detected source language defaults to English as the most commonly
  // requested target for US immigration/court filings.
  if (data.detectedLanguage === 'en') targetLanguage = 'tr';
  else if (data.detectedLanguage === 'tr') targetLanguage = 'en';
  else targetLanguage = 'en';
