if (decision === 'Approve with Edits' && corrected.trim()) {
  finalPages = finalPages.map((page, i) => ({
    ...page,
    text: i === 0 ? corrected.trim() : page.text,
    reviewerCorrected: true,
  }));
}

const attEmail = form['Filing Attorney Email'] || pipeline.filingAttorneyEmail || '';

