return [{ json: { ...pipeline, deliveryStatus: 'DELIVERED', markedAt: new Date().toISOString() } }];

// Move Source to Archive outputs Drive metadata, not pipeline data.
// Restore full pipeline from Merge Doc Result for downstream email nodes.
const pipeline = $('Merge Doc Result').first().json;
return [{ json: pipeline }];

